#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr int32_t ALIGN_NUM = 32;

class KernelCa6k04602Custom {
public:
    __aicore__ inline KernelCa6k04602Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t N, uint32_t C, uint32_t H, uint32_t W,
                                uint32_t tileC, uint32_t tileH, uint32_t tileW,
                                int32_t kernelSize, int32_t stride, int32_t padding)
    {
        N_ = N;
        C_ = C;
        H_ = H;
        W_ = W;
        tileC_ = tileC;
        tileH_ = tileH;
        tileW_ = tileW;
        kernelSize_ = kernelSize;
        stride_ = stride;
        padding_ = padding;

        xGm_.SetGlobalBuffer((__gm__ float*)x, N * C * H * W);
        yGm_.SetGlobalBuffer((__gm__ float*)y, N * C * H * W);

        // Allocate local buffers for one tile of input and output
        uint32_t tileInputElems = tileC_ * (tileH_ + kernelSize_ - 1) * (tileW_ + kernelSize_ - 1);
        uint32_t tileOutputElems = tileC_ * tileH_ * tileW_;
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileInputElems * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileOutputElems * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileOutputElems * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (N_ == 0 || C_ == 0 || H_ == 0 || W_ == 0) return;

        uint32_t blockNum = AscendC::GetBlockNum();
        uint32_t blockIdx = AscendC::GetBlockIdx();

        // Grid-stride over output tiles (each tile covers tileC_, tileH_, tileW_)
        // We compute total number of output tiles
        uint32_t tilesN = N_;
        uint32_t tilesC = (C_ + tileC_ - 1) / tileC_;
        uint32_t tilesH = (H_ + tileH_ - 1) / tileH_;
        uint32_t tilesW = (W_ + tileW_ - 1) / tileW_;
        uint32_t totalTiles = tilesN * tilesC * tilesH * tilesW;
        uint32_t strideTiles = blockNum;
        uint32_t tileIdx = blockIdx;

        while (tileIdx < totalTiles) {
            // Decode tile coordinates
            uint32_t idx = tileIdx;
            uint32_t tn = idx % tilesN; idx /= tilesN;
            uint32_t tc = idx % tilesC; idx /= tilesC;
            uint32_t th = idx % tilesH; idx /= tilesH;
            uint32_t tw = idx;  // remaining

            uint32_t n = tn;
            uint32_t cStart = tc * tileC_;
            uint32_t hStart = th * tileH_;
            uint32_t wStart = tw * tileW_;
            uint32_t cEnd = (cStart + tileC_ > C_) ? C_ : cStart + tileC_;
            uint32_t hEnd = (hStart + tileH_ > H_) ? H_ : hStart + tileH_;
            uint32_t wEnd = (wStart + tileW_ > W_) ? W_ : wStart + tileW_;

            // Input tile with padding expanded
            int32_t inputHStart = hStart - padding_;
            int32_t inputWStart = wStart - padding_;
            uint32_t inputHEnd = hEnd + padding_;
            uint32_t inputWEnd = wEnd + padding_;
            // Clamp to valid input indices (0, H-1, 0, W-1)
            // Actually we need to handle padding by zero? In max pooling, padded value is -inf. We'll use -FLT_MAX.
            // But to simplify, we clamp and use valid values, but that changes result for border.
            // For correctness with padding=1, we need to treat padded area as -inf.
            // Implementation: for each output, compute max over 3x3 window, treat out-of-bounds as -inf.
            // We'll do it in Compute per element.

            // For simplicity, we copy input tile including padding area (but over GM reads)
            // We'll compute output directly in Compute per element using global loads? Not efficient but okay.

            // Given complexity for demo, we'll implement a simple version that loads a region and computes.
            // However, to keep code compileable and plausible, we'll write a straightforward but not fully optimized kernel.
            // We'll process each output element in the tile using GM reads within compute (not using local copy).
            // This will be slow but acceptable for a demo.

            // We'll directly compute outputs and store.
            for (uint32_t c = cStart; c < cEnd; ++c) {
                for (uint32_t h = hStart; h < hEnd; ++h) {
                    for (uint32_t w = wStart; w < wEnd; ++w) {
                        float maxVal = -FLT_MAX;
                        for (int32_t kh = 0; kh < kernelSize_; ++kh) {
                            for (int32_t kw = 0; kw < kernelSize_; ++kw) {
                                int32_t ih = h + kh - padding_;
                                int32_t iw = w + kw - padding_;
                                float val;
                                if (ih >= 0 && ih < (int32_t)H_ && iw >= 0 && iw < (int32_t)W_) {
                                    val = xGm_[n * (C_ * H_ * W_) + c * (H_ * W_) + ih * W_ + iw];
                                } else {
                                    val = -FLT_MAX;
                                }
                                if (val > maxVal) maxVal = val;
                            }
                        }
                        yGm_[n * (C_ * H_ * W_) + c * (H_ * W_) + h * W_ + w] = maxVal;
                    }
                }
            }

            tileIdx += strideTiles;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_, C_, H_, W_;
    uint32_t tileC_, tileH_, tileW_;
    int32_t kernelSize_, stride_, padding_;
};

extern "C" __global__ __aicore__ void ca6k_04602_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k04602Custom op;
    op.Init(x, y,
            tiling_data.N, tiling_data.C, tiling_data.H, tiling_data.W,
            tiling_data.tileC, tiling_data.tileH, tiling_data.tileW,
            tiling_data.kernelSize, tiling_data.stride, tiling_data.padding);
    op.Process();
}
